#!/bin/bash
set -e
echo "📝 Backlog Webhook + タイトル変更対応 適用..."
echo ""    | base64 -d > backend/src/services/feedbackService.ts
echo ""   | base64 -d > backend/src/controllers/feedbackController.ts
echo "" | base64 -d > backend/src/routes/feedbackRoutes.ts

cd backend
ERRS=$(npx tsc --noEmit 2>&1 | grep -c "error TS" || true)
cd ..
echo "Backend エラー数: ${ERRS}"

if [ "${ERRS}" = "0" ]; then
    git add backend/src/services/feedbackService.ts \
            backend/src/controllers/feedbackController.ts \
            backend/src/routes/feedbackRoutes.ts
    git diff --cached --quiet || git commit -m "feat: Backlog Webhook タイトル変更・ステータス同期・コメント反映"
    git push origin main
    echo "pushed!"
    dt-restart
else
    cd backend && npx tsc --noEmit 2>&1 | grep "error TS" | head -10 || true; cd ..
fi
